UPDATE cm_classroom_student
SET dynamic_state = #{dynamicState}
WHERE id = #{classroomStudentId}

mapper.select:
SELECT AVG(a.libScore) as avgLibScore,
AVG(a.libStuScore) as avgLibStuScore,
b.keywordid as id
FROM ai_in_stu_ans_info a
JOIN cm_kwadict b
ON a.kwaId = b.id
WHERE a.paperId IN

    #{item.paperId}

AND a.courseId = #{courseId}

    AND a.stuId = #{stuId}

AND a.classroomId = #{classroomId}
GROUP BY b.keywordid

SELECT AVG(a.libScore) as avgLibScore,
AVG(a.libStuScore) as avgLibStuScore,
b.abilityid as id
FROM ai_in_stu_ans_info a
JOIN cm_kwadict b
ON a.kwaId = b.id
WHERE a.paperId IN

    #{item.paperId}

AND a.courseId = #{courseId}

    AND a.stuId = #{stuId}

AND a.classroomId = #{classroomId}
GROUP BY b.abilityid

SELECT AVG(a.libScore) as avgLibScore,
AVG(a.libStuScore) as avgLibStuScore,
b.unitId as id
FROM ai_in_stu_ans_info a
JOIN cm_course_unit_kwa b
ON a.kwaId = b.kwaId
WHERE a.paperId IN

    #{item.paperId}

AND a.courseId = #{courseId}

    AND a.stuId = #{stuId}

AND a.classroomId = #{classroomId}
GROUP BY b.unitId

SELECT b.id as testId, b.paperId as paperId, b.name as testName, b.paperName as paperName, b.classroomId as classroomId, b.classroomName as classroomName, b.creatorId as creatorId, temp.creator as creator, b.creatTime as createTime FROM cm_classroom a JOIN pm_test b ON a.id = b.classroomId JOIN (SELECT id, username as creator FROM st_users) temp ON temp.id = b.creatorId
b.status = 1 AND a.courseId = #{courseId}
AND a.id = #{classroomId}
AND (b.name LIKE CONCAT('%', #{search}, '%') OR b.paperName LIKE CONCAT('%', #{search}, '%') OR b.classroomName LIKE CONCAT('%', #{search}, '%') OR b.creatTime LIKE CONCAT('%', #{search}, '%') OR temp.creator LIKE CONCAT('%', #{search}, '%') )

SELECT courseChineseName as courseName
FROM cm_course
WHERE id = #{courseId}

SELECT username as creator
FROM st_users
WHERE id = #{creatorId}

SELECT id as classroomId, classroomName, termId, courseId, teacherName, creatorName as creator, labTeacher, practiceTeacher FROM cm_classroom
AND courseId = #{courseId}
AND classroomName LIKE CONCAT('%', #{classroomName}, '%')

SELECT termname as termName
FROM cm_term
WHERE id = #{termId}

SELECT id as paperId, createTime
FROM pm_testpaper
WHERE id = #{testId}

SELECT kwaId as id, datavalue AS dataValue, kwaName FROM tm_testquelib_kwa
WHERE libId IN (
SELECT libId FROM pm_testpaper_questions
WHERE paperId IN

    #{item.paperId}

)

