    #{item.paperId}

AND a.courseId = #{courseId}
AND a.stuId = #{stuId}
AND a.classroomId = #{classroomId}
GROUP BY b.id

SELECT userId FROM cm_classroom_student
WHERE classroomId = #{classroomId}
AND dynamic_state = 1

SELECT paper_id as paperId, create_time createTime,`row`
FROM ai_calculate_paper
WHERE classroom_id = #{classroomId}

SELECT id FROM cm_classroom_student
WHERE classroomId = #{classroomId}
    AND userId = #{stuId}

SELECT id FROM ai_in_stu_ans_info
WHERE classroomId = #{classroomId}
    AND courseId = #{courseId}
    AND paperId = #{paperId}
    AND stuId = #{stuId}

SELECT DISTINCT num
FROM ai_stu_portrait_ability
WHERE stu_id = #{stuId}
  AND classroom_id = #{classroomId}
  AND course_id = #{courseId}
ORDER BY num ASC

